#!/usr/bin/env node
import { parseArgs } from "node:util";

import { packageExtension } from "./package.js";
import { runExtension } from "./run.js";

// Load .env from the cwd if present, so EXTENSION_HOST_PATH (and other vars)
// configured per-project are picked up without a separate dotenv dependency.
try {
  process.loadEnvFile();
} catch {
  // No .env file — that's fine, env vars can come from the shell instead.
}

const HELP = `Usage: extensions-cli <command> [options] [dir]

Commands:
  run [dir]         Run an extension in Live's Extension Host. Reads
                    EXTENSION_HOST_PATH from the environment (or .env).
                    Options:
                      --live <path>          Override EXTENSION_HOST_PATH
                      --storage-directory <path>
                      --temp-directory <path>
                      --inspect              Enable VS Code debugging (--inspect-brk)

  package [dir]     Build a .ablx archive from a built extension.
                    Options:
                      -o, --output <path>    Output .ablx path
                      -i, --include <p...>   Additional files/dirs to bundle

  help              Show this message
`;

function printHelpAndExit(code: number): never {
  process.stdout.write(HELP);
  process.exit(code);
}

async function main(argv: string[]): Promise<void> {
  const [command, ...rest] = argv;
  if (
    !command ||
    command === "help" ||
    command === "-h" ||
    command === "--help"
  ) {
    printHelpAndExit(command ? 0 : 1);
  }

  switch (command) {
    case "run": {
      const { values, positionals } = parseArgs({
        args: rest,
        allowPositionals: true,
        options: {
          live: { type: "string" },
          "storage-directory": { type: "string" },
          "temp-directory": { type: "string" },
          inspect: { type: "boolean" },
        },
      });
      const live = values.live ?? process.env.EXTENSION_HOST_PATH;
      if (!live) {
        console.error(
          "No Extension Host path provided.\n" +
            "Set EXTENSION_HOST_PATH in your environment (e.g. in a .env " +
            "file) or pass --live <path>.",
        );
        process.exit(1);
      }
      runExtension(positionals[0], {
        live,
        ...(values["storage-directory"] !== undefined && {
          storageDirectory: values["storage-directory"],
        }),
        ...(values["temp-directory"] !== undefined && {
          tempDirectory: values["temp-directory"],
        }),
        ...(values.inspect && { inspect: true }),
      });
      return;
    }
    case "package": {
      const { values, positionals } = parseArgs({
        args: rest,
        allowPositionals: true,
        options: {
          output: { type: "string", short: "o" },
          include: { type: "string", short: "i", multiple: true },
        },
      });
      await packageExtension(positionals[0], values.output, values.include);
      return;
    }
    default:
      console.error(`Unknown command: ${command}\n`);
      printHelpAndExit(1);
  }
}

main(process.argv.slice(2)).catch((err) => {
  console.error(err instanceof Error ? err.message : err);
  process.exit(1);
});
